content.text:
The syntax of a `for...in` loop is:
```javascript
for (variable in object) {
  // code to execute
}
```
- **Variable**: Represents the key of each property in the object.
- **Object**: The object whose enumerable properties are iterated.
- The loop iterates over each enumerable property one by one.

content.code:
// Basic for...in loop example
const person = {
  name: 'Ali',
  age: 25,
  job: 'Engineer'
};
for (let key in person) {
  console.log(`Key: ${key}, Value: ${person[key]}`);
}
// Output:
// Key: name, Value: Ali
// Key: age, Value: 25
// Key: job, Value: Engineer

// for...in loop with an array
const fruits = ['apple', 'pear', 'orange'];
for (let index in fruits) {
  console.log(`Index: ${index}, Value: ${fruits[index]}`);
}
// Output:
// Index: 0, Value: apple
// Index: 1, Value: pear
// Index: 2, Value: orange

// break and continue example
const person = {
  name: 'Aygun',
  age: 30,
  job: 'Teacher'
};
for (let key in person) {
  if (key === 'age') {
    break; // stops the loop
  }
  console.log(`Key: ${key}, Value: ${person[key]}`);
}
// Output:
// Key: name, Value: Aygun

for (let key in person) {
  if (key === 'age') {
    continue; // skips age
  }
  console.log(`Key: ${key}, Value: ${person[key]}`);
}
// Output:
// Key: name, Value: Aygun
// Key: job, Value: Teacher

// hasOwnProperty with for...in example
const person = {
  name: 'Elvin',
  age: 28
};
Object.prototype.extra = 'Extra property';
for (let key in person) {
  if (person.hasOwnProperty(key)) {
    console.log(`Key: ${key}, Value: ${person[key]}`);
  }
}
// Output:
// Key: name, Value: Elvin
// Key: age, Value: 28

// Error-prone example
// Error: Inherited properties are included
const person = {
  name: 'Samad',
  age: 22
};
Object.prototype.extra = 'Extra property';
for (let key in person) {
  console.log(`Key: ${key}, Value: ${person[key]}`);
}
// Output (error):
// Key: name, Value: Samad
// Key: age, Value: 22
// Key: extra, Value: Extra property

// Correct approach
const person2 = {
  name: 'Samad',
  age: 22
};
for (let key in person2) {
  if (person2.hasOwnProperty(key)) {
    console.log(`Key: ${key}, Value: ${person2[key]}`);
  }
}
// Output:
// Key: name, Value: Samad
// Key: age, Value: 22

