content.text:
Синтаксис цикла `for...in` следующий:
```javascript
for (переменная in объект) {
  // код для выполнения
}
```
- **Переменная**: Представляет ключ каждого свойства объекта.
- **Объект**: Объект, чьи перечисляемые свойства перебираются.
- Цикл перебирает каждое перечисляемое свойство по очереди.

content.code:
// Пример базового цикла for...in
const person = {
  name: 'Али',
  age: 25,
  job: 'Инженер'
};
for (let key in person) {
  console.log(`Ключ: ${key}, Значение: ${person[key]}`);
}
// Вывод:
// Ключ: name, Значение: Али
// Ключ: age, Значение: 25
// Ключ: job, Значение: Инженер

// Цикл for...in с массивом
const fruits = ['яблоко', 'груша', 'апельсин'];
for (let index in fruits) {
  console.log(`Индекс: ${index}, Значение: ${fruits[index]}`);
}
// Вывод:
// Индекс: 0, Значение: яблоко
// Индекс: 1, Значение: груша
// Индекс: 2, Значение: апельсин

// Пример break и continue
const person = {
  name: 'Айгюн',
  age: 30,
  job: 'Учитель'
};
for (let key in person) {
  if (key === 'age') {
    break; // останавливает цикл
  }
  console.log(`Ключ: ${key}, Значение: ${person[key]}`);
}
// Вывод:
// Ключ: name, Значение: Айгюн

for (let key in person) {
  if (key === 'age') {
    continue; // пропускает age
  }
  console.log(`Ключ: ${key}, Значение: ${person[key]}`);
}
// Вывод:
// Ключ: name, Значение: Айгюн
// Ключ: job, Значение: Учитель

// Пример hasOwnProperty с for...in
const person = {
  name: 'Эльвин',
  age: 28
};
Object.prototype.extra = 'Дополнительное свойство';
for (let key in person) {
  if (person.hasOwnProperty(key)) {
    console.log(`Ключ: ${key}, Значение: ${person[key]}`);
  }
}
// Вывод:
// Ключ: name, Значение: Эльвин
// Ключ: age, Значение: 28

// Пример с ошибкой
// Ошибка: Унаследованные свойства включаются
const person = {
  name: 'Самед',
  age: 22
};
Object.prototype.extra = 'Дополнительное свойство';
for (let key in person) {
  console.log(`Ключ: ${key}, Значение: ${person[key]}`);
}
// Вывод (ошибка):
// Ключ: name, Значение: Самед
// Ключ: age, Значение: 22
// Ключ: extra, Значение: Дополнительное свойство

// Правильный подход
const person2 = {
  name: 'Самед',
  age: 22
};
for (let key in person2) {
  if (person2.hasOwnProperty(key)) {
    console.log(`Ключ: ${key}, Значение: ${person2[key]}`);
  }
}
// Вывод:
// Ключ: name, Значение: Самед
// Ключ: age, Значение: 22

